// ── Lecture du body ──────────────────────────────────────────
const body = $input.item.json.body || $input.item.json;
const deployment_id    = body.deployment_id;
const vague_ids        = body.vague_ids || [];
const message_override = body.message_override || '';
const isTest           = body.test === true;
const testDest         = body.test_destinataire || null;

if (!deployment_id) {
  return { json: { skip: true, reason: 'deployment_id manquant' } };
}
if (!isTest && !vague_ids.length) {
  return { json: { skip: true, reason: 'vague_ids manquants (mode réel)' } };
}

const SUPA_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const H = { 'apikey': SUPA_KEY, 'Authorization': 'Bearer ' + SUPA_KEY, 'Content-Type': 'application/json' };

if (isTest) {
  console.log('🧪 Mode TEST — destinataire unique:', testDest?.email, testDest?.telephone);
}

// ── 1. Charger le déploiement ─────────────────────────────────
const deps = await this.helpers.httpRequest({
  method: 'GET',
  url: `https://jtzwkmcfarxptpcoaxxl.supabase.co/rest/v1/deployments?id=eq.${deployment_id}&select=id,identifiant,nom,lieu,date_debut,date_fin,nb_personnes_par_vague,point_rassemblement`,
  headers: H
});
const dep = deps?.[0] || {};
console.log('Déploiement:', dep.nom, '| Lieu:', dep.lieu);

// ── 2. Charger les vagues (si pas test ou test avec vagues) ──
let vagues = [];
if (vague_ids.length) {
  vagues = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://jtzwkmcfarxptpcoaxxl.supabase.co/rest/v1/vagues?or=(${vague_ids.map(id=>`id.eq.${id}`).join(',')})&select=id,identifiant,numero,date_debut,date_fin,nb_personnes_requis`,
    headers: H
  });
  console.log('Vagues chargées:', vagues?.length || 0);
}

// Résumé des rotations pour le message
const rotationsTexte = (vagues || []).map(v => {
  const id = v.identifiant || `Rotation #${v.numero}`;
  return `${id} : ${v.date_debut} → ${v.date_fin}${v.nb_personnes_requis ? ' (' + v.nb_personnes_requis + ' pers.)' : ''}`;
}).join('\n');

const v0 = vagues?.[0] || {};
const dateDebutAff = v0.date_debut ? v0.date_debut.split('-').reverse().join('/') : '';
const dateFinAff   = v0.date_fin   ? v0.date_fin.split('-').reverse().join('/')   : '';
const vagNom = v0.identifiant || (v0.numero ? `Rotation #${v0.numero}` : 'Rotation');

// ── 3. TEST ou RÉEL : déterminer les destinataires ───────────
let reservistes = [];

if (isTest) {
  if (!testDest?.email && !testDest?.telephone) {
    return { json: { skip: true, reason: 'TEST sans email ni telephone' } };
  }
  reservistes = [{
    benevole_id: testDest.benevole_id || 'TEST',
    prenom:      testDest.prenom || 'Test',
    nom:         testDest.nom || '',
    email:       testDest.email || null,
    telephone:   testDest.telephone || null
  }];
} else {
  // Réservistes disponibles (disponibilites_v2 où disponible=true)
  const dispos = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://jtzwkmcfarxptpcoaxxl.supabase.co/rest/v1/disponibilites_v2?deployment_id=eq.${deployment_id}&disponible=eq.true&select=benevole_id`,
    headers: H
  });
  const idsUniques = [...new Set((dispos || []).map(d => d.benevole_id))];
  console.log('Réservistes disponibles:', idsUniques.length);
  if (!idsUniques.length) {
    return { json: { skip: true, reason: 'Aucun réserviste disponible trouvé' } };
  }
  const inFilter = idsUniques.map(id => `benevole_id.eq.${id}`).join(',');
  reservistes = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://jtzwkmcfarxptpcoaxxl.supabase.co/rest/v1/reservistes?or=(${inFilter})&select=benevole_id,prenom,nom,email,telephone`,
    headers: H
  });
  console.log('Réservistes chargés:', reservistes?.length || 0);
}

const timestamp_envoi = new Date().toISOString();

// ── 3b. Séparer le contenu SMS du contenu courriel ─────────
// Si le message contient un bloc ---SMS--- ... ---FIN---, on le retire
// du message destiné au courriel (sinon il apparaîtrait brut dedans).
const message_override_clean = message_override
  ? message_override.replace(/---SMS---[\s\S]*?---FIN---\s*\n?/i, '').trim()
  : '';

// ── 4. Envoyer SMS à chaque réserviste ───────────────────────
const resultats = [];

for (const r of (reservistes || [])) {
  if (!r.prenom) continue;

  if (r.telephone) {
    try {
      const smsPrefix = isTest ? '[TEST] ' : '';
      // Détection du bloc SMS dédié dans le message : ---SMS--- ... ---FIN---
      // Si présent : ce contenu est utilisé pour le SMS.
      // Sinon : on tombe en fallback sur les 3 premières lignes (ancienne logique).
      const smsMatch = message_override && message_override.match(/---SMS---\s*\n([\s\S]*?)\n---FIN---/i);
      let smsBody;
      if (smsMatch) {
        smsBody = smsPrefix + smsMatch[1].trim().substring(0, 160 - smsPrefix.length);
      } else if (message_override) {
        smsBody = smsPrefix + message_override.split('\n').slice(0, 3).join(' ').substring(0, 160 - smsPrefix.length);
      } else {
        smsBody = `${smsPrefix}RIUSC – Mobilisation confirmée\n${dep.nom || ''}${dep.lieu ? ' · ' + dep.lieu : ''}\n${vagNom} : ${dateDebutAff}${dateFinAff ? ' → ' + dateFinAff : ''}\nhttps://portail.riusc.ca/mobilisation`;
      }

      await this.helpers.httpRequest({
        method: 'POST',
        url: `https://api.twilio.com/2010-04-01/Accounts/${$env.TWILIO_ACCOUNT_SID}/Messages.json`,
        auth: { username: $env.TWILIO_ACCOUNT_SID, password: $env.TWILIO_AUTH_TOKEN },
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: `From=%2B14388073137&To=%2B1${r.telephone.replace(/\D/g,'')}&Body=${encodeURIComponent(smsBody)}`
      });
      console.log(`${isTest ? '🧪 TEST ' : ''}SMS mobilisation envoyé à`, r.telephone);
    } catch (e) {
      console.log('Erreur SMS', r.benevole_id, e.message);
    }
  }

  resultats.push({
    isTest,
    benevole_id:      r.benevole_id,
    prenom:           r.prenom,
    nom:              r.nom,
    email:            r.email,
    telephone:        r.telephone,
    nom_deploiement:  (isTest ? '[TEST] ' : '') + (dep.nom || ''),
    lieu:             dep.lieu || '',
    point_rassemblement: dep.point_rassemblement || '',
    date_debut_dep:   dep.date_debut || '',
    vag_nom:          vagNom,
    date_debut_vag:   dateDebutAff,
    date_fin_vag:     dateFinAff,
    rotations_texte:  rotationsTexte,
    message_override: message_override_clean,
    deployment_id,
    timestamp_envoi
  });
}

if (!resultats.length) {
  return { json: { skip: true, reason: 'Aucun réserviste avec profil complet trouvé' } };
}

return resultats.map(r => ({ json: r }));

// Met à jour ciblages.statut → 'mobilise' dans Supabase
const data = $input.item.json;
if (data.skip) return { json: { skip: true } };

// 🧪 Mode TEST : on ne touche PAS à la DB
if (data.isTest) {
  console.log('🧪 TEST — skip update DB pour', data.benevole_id);
  return { json: { success: true, benevole_id: data.benevole_id, timestamp: data.timestamp_envoi, isTest: true } };
}

const SUPA_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const H = { 'apikey': SUPA_KEY, 'Authorization': 'Bearer ' + SUPA_KEY, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' };

try {
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: `https://jtzwkmcfarxptpcoaxxl.supabase.co/rest/v1/ciblages?niveau=eq.deploiement&reference_id=eq.${data.deployment_id}&benevole_id=eq.${data.benevole_id}`,
    headers: H,
    body: JSON.stringify({ statut: 'mobilise', updated_at: data.timestamp_envoi })
  });
  console.log('Supabase ciblage mobilisé:', data.benevole_id);
} catch (e) {
  console.log('Erreur Supabase update ciblage:', e.message);
}

return { json: { success: true, benevole_id: data.benevole_id, timestamp: data.timestamp_envoi } };

// Agrège les résultats et répond au portail
const items = $input.all();
const nb_envoyes = items.filter(i => i.json.success).length;
const nb_erreurs = items.filter(i => i.json.skip).length;
const isTest = items.some(i => i.json.isTest);
console.log(`${isTest ? '🧪 TEST ' : ''}Mobilisation terminée: ${nb_envoyes} envoyé(s), ${nb_erreurs} ignoré(s)`);
return { json: { done: true, nb_envoyes, nb_erreurs, isTest } };
